/**
 * @fileoverview Dropdown component definition for JIT pipeline.
 * @module module/Dropdown.def
 */

import { PART } from './Dropdown/constants.js';

export const DropdownDef = {
    name: 'Dropdown',
    tag: 'rui-dropdown',

    tokens: {
        prefix: 'dd',
        tokens: {
            'bg':              { ref: 'color.bg',              description: 'Menu background' },
            'border':          { ref: 'color.border',          description: 'Menu border' },
            'radius':          { ref: 'radius.lg',             description: 'Menu border radius' },
            'shadow':          { ref: 'shadow.lg',             description: 'Menu shadow' },
            'min-width':       { value: '12rem',               description: 'Minimum menu width' },
            'menu-py':         { value: '0.25rem',             description: 'Menu vertical padding' },

            // Item
            'item-px':         { ref: 'spacing.3',             description: 'Item horizontal padding' },
            'item-py':         { ref: 'spacing.2',             description: 'Item vertical padding' },
            'item-gap':        { ref: 'spacing.2',             description: 'Gap between icon and label' },
            'item-font-size':  { ref: 'font.size-sm',          description: 'Item font size' },
            'item-text':       { ref: 'color.text',            description: 'Item text color' },
            'item-hover-bg':   { ref: 'color.hover',           description: 'Item hover background' },

            // Icon
            'icon-text':       { ref: 'color.text-secondary',  description: 'Icon color' },

            // Header
            'header-size':     { ref: 'font.size-xs',          description: 'Header font size' },
            'header-text':     { ref: 'color.text-muted',      description: 'Header text color' },
        },
    },

    states: {
        initial: 'closed',
        states: {
            closed: { on: { OPEN: 'open' } },
            open:   { on: { CLOSE: 'closed' } },
        },
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.TRIGGER]: PART.TRIGGER,
        [PART.MENU]: PART.MENU,
        [PART.ITEM]: PART.ITEM,
        [PART.DIVIDER]: PART.DIVIDER,
        [PART.LABEL]: PART.LABEL,
        [PART.ICON]: PART.ICON,
        [PART.HEADER]: PART.HEADER,
    },

    observedAttrs: ['anchor', 'offset'],
};
