/**
 * @fileoverview Dropdown component — modular entry point.
 * @module module/Dropdown
 */

import { default as razyui } from '../../index.js';
import { DEFAULTS, CLS } from './constants.js';
import { setupDOM, removeMenu } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
import { attachOutsideClick } from '../shared/outsideClick.js';
import { positionFloating } from '../shared/positionFloating.js';

const Dropdown = class {
    #root   = null;
    #destroyed = false;
    #config = {};
    #els    = {};
    #isOpen = false;
    #eventAC     = new AbortController();
    #outsideAC   = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Dropdown: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#els = setupDOM(root, this.#config);
        this.#init();

        // Apply min-width if specified
        if (this.#config.minWidth) {
            this.#els.menu.style.minWidth = this.#config.minWidth;
        }
    }

    #init() {
        const sig = { signal: this.#eventAC.signal };
        const triggerEl = this.#els.triggerEl;

        // Toggle on trigger click
        if (triggerEl) {
            triggerEl.addEventListener('click', (e) => {
                e.stopPropagation();
                this.toggle();
            }, sig);
        }

        // Close on outside click — handled per open/close cycle via attachOutsideClick

        // Keyboard navigation
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && this.#isOpen) { this.close(); return; }
            if (!this.#isOpen) return;

            const items = [...this.#els.menu.querySelectorAll('.' + CLS.ITEM + ':not(.' + CLS.DISABLED + ')')];
            if (!items.length) return;
            const active = items.findIndex(el => el.classList.contains(CLS.FOCUSED));

            if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
                e.preventDefault();
                const dir = e.key === 'ArrowDown' ? 1 : -1;
                const next = active < 0 ? 0 : (active + dir + items.length) % items.length;
                items.forEach(el => el.classList.remove(CLS.FOCUSED));
                items[next].classList.add(CLS.FOCUSED);
                items[next].scrollIntoView({ block: 'nearest' });
            } else if (e.key === 'Home') {
                e.preventDefault();
                items.forEach(el => el.classList.remove(CLS.FOCUSED));
                items[0].classList.add(CLS.FOCUSED);
            } else if (e.key === 'End') {
                e.preventDefault();
                items.forEach(el => el.classList.remove(CLS.FOCUSED));
                items[items.length - 1].classList.add(CLS.FOCUSED);
            } else if (e.key === 'Enter' || e.key === ' ') {
                if (active >= 0) { e.preventDefault(); items[active].click(); }
            }
        }, sig);

        // Enter/Space on trigger to toggle
        if (triggerEl) {
            triggerEl.addEventListener('keydown', (e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    this.toggle();
                }
            }, sig);
        }

        // Item click handlers
        for (const { el: itemEl, config: item } of this.#els.itemEls) {
            itemEl.addEventListener('click', (e) => {
                if (item.disabled) { e.preventDefault(); return; }
                item.onClick?.(e);
                emitEvent(this.#root[0], 'select', { item });
                if (this.#config.closeOnSelect) this.close();
            }, sig);
        }
    }

    /* ---- Public API ---- */
    open() {
        if (this.#isOpen) return;
        this.#isOpen = true;

        const anchorEl = this.#els.triggerEl || this.#root[0];
        positionFloating(this.#els.menu, anchorEl, {
            strategy: 'fixed',
            gap:      this.#config.offset,
            flip:     true,
            width:    'min-match',
        });

        zIndexRegistry.acquire(this.#els.menu);
        this.#root.addClass(CLS.OPEN);
        this.#els.menu.classList.add(CLS.OPEN);
        if (this.#els.triggerEl) this.#els.triggerEl.setAttribute('aria-expanded', 'true');

        // Attach outside-click listener for the open cycle
        if (this.#config.closeOnOutside) {
            this.#outsideAC = attachOutsideClick(
                this.#root[0],
                this.#els.menu,
                () => this.close(),
                { guardMs: 50 },
            );
        }

        emitEvent(this.#root[0], 'open');
    }

    close() {
        if (!this.#isOpen) return;
        this.#isOpen = false;

        this.#outsideAC?.abort();
        this.#outsideAC = null;

        this.#root.removeClass(CLS.OPEN);
        this.#els.menu.classList.remove(CLS.OPEN);
        // Clear keyboard focus
        this.#els.menu.querySelectorAll('.' + CLS.FOCUSED).forEach(el => el.classList.remove(CLS.FOCUSED));
        if (this.#els.triggerEl) this.#els.triggerEl.setAttribute('aria-expanded', 'false');
        zIndexRegistry.release(this.#els.menu);
        emitEvent(this.#root[0], 'close');
    }

    toggle() {
        this.#isOpen ? this.close() : this.open();
    }

    get isOpen() { return this.#isOpen; }

    getControl() {
        const self = this;
        return {
            open:    () => self.open(),
            close:   () => self.close(),
            toggle:  () => self.toggle(),
            get isOpen() { return self.isOpen; },
            destroy: () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        this.#outsideAC?.abort();
        zIndexRegistry.release(this.#els.menu);
        removeMenu(this.#els.menu);
    }
};

export default Dropdown;
