/**
 * @fileoverview Dropdown barrel.
 * @module module/Dropdown
 */
import { default as razyui } from '../index.js';
import { DropdownDef as DEF } from './Dropdown.def.js';
import Dropdown from './Dropdown/index.js';

razyui.Dropdown = Dropdown;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Dropdown);
}

export default Dropdown;

export const stylesheet = null;
